// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check title screen name', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check title screen name', async function() {
    // Test name: Check title screen name
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/evaluation-reference-basic | 
    await driver.get("http://localhost:4200/user/evaluation-reference-basic");

    // 2 | setWindowSize | 1936x1056 | 
    await driver.manage().window().setRect({ width: 1936, height: 1056 });

    // 3 | click | css=.ant-typography:nth-child(1) | 
    await driver.findElement(By.css(".ant-typography:nth-child(1)")).click();

    // 4 | click | css=.ant-typography:nth-child(1) | 
    await driver.findElement(By.css(".ant-typography:nth-child(1)")).click();

    // 5 | doubleClick | css=.ant-typography:nth-child(1) | 
    {
      const element = await driver.findElement(By.css(".ant-typography:nth-child(1)"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 6 | click | css=.ant-typography:nth-child(1) | 
    await driver.findElement(By.css(".ant-typography:nth-child(1)")).click();

    // 7 | verifyText | css=.ant-typography:nth-child(1) | 基本スキル評価項目
    assert(await driver.findElement(By.css(".ant-typography:nth-child(1)")).getText() == "基本スキル評価項目");
  });
});
